    int n = nums.length;
    // Preprocess the array to build a frequency map for each index
    // We'll use a list of hash maps, where each map corresponds to the frequency of elements up to index i
    java.util.Map<Long, Integer>[] freqMaps = new java.util.HashMap[n + 1];

    for (int i = 0; i <= n; i++) {
        freqMaps[i] = new java.util.HashMap<>();
    }

    // Build the prefix frequency maps
    for (int i = 0; i < n; i++) {
        long num = nums[i];
        // Copy the previous frequency map and update with the current number
        java.util.Map<Long, Integer> prevMap = freqMaps[i];
        java.util.Map<Long, Integer> currMap = freqMaps[i + 1];
        for (java.util.Map.Entry<Long, Integer> entry : prevMap.entrySet()) {
